import { useMemo, useState } from "react";

const GREEN  = "#1E4730";
const TAN    = "#C49145";
const CREAM  = "#F5EDD5";
const WHITE  = "#FFFDF7";
const MUTED  = "#7A8B7A";
const BORDER = "#DDD5C0";
const LGREEN = "#EAF2E6";
const LOGO = "data:image/png;base64,";

// 기존 Apps Script 배포 URL입니다. Code.gs를 교체한 뒤 같은 배포를 새 버전으로 업데이트하세요.
const SUBMIT_ENDPOINT = "https://script.google.com/macros/s/AKfycbz566Qnfo7PcNfD2IPRK4kOahzDtOYkk_zpKam3jz7AygT2YgR5XrNe8P0o1F6FYCI/exec";
const KAKAO_CHAT_URL = "http://pf.kakao.com/_qxixjGX/chat";

const STEPS = [
  { id:"guardian",    emoji:"👤", title:"보호자 연락처를 알려주세요",       subtitle:"추천 결과와 상담 안내에만 사용해요" },
  { id:"dogBasic",    emoji:"🐶", title:"아이 기본 정보를 알려주세요",      subtitle:"체중과 나이는 입학 조건 판단에 중요해요" },
  { id:"dogCondition",emoji:"💉", title:"성별·중성화·접종 상태는요?",        subtitle:"업체별 입학 제한 확인을 위한 항목이에요" },
  { id:"area",        emoji:"📍", title:"어느 동네에 거주하세요?",           subtitle:"동 이름까지 적으면 픽업 범위 판단이 정확해요" },
  { id:"service",     emoji:"🏫", title:"어떤 돌봄을 찾고 계세요?",         subtitle:"여러 개 선택할 수 있어요" },
  { id:"pickup",      emoji:"🚐", title:"픽업·드랍이 필요하세요?",           subtitle:"직접 등하원 가능 여부도 함께 확인해요" },
  { id:"personality", emoji:"💬", title:"아이 성향을 골라주세요",            subtitle:"여러 개 선택할 수 있어요" },
  { id:"health",      emoji:"🩺", title:"건강·행동 관련 참고사항이 있나요?",  subtitle:"안전한 매칭을 위해 솔직하게 적어주세요" },
  { id:"priority",    emoji:"⭐", title:"가장 중요하게 보는 조건은요?",      subtitle:"여러 개 선택할 수 있어요" },
  { id:"notes",       emoji:"📝", title:"추가로 원하는 점이 있나요?",        subtitle:"예산과 이용 희망 시기도 알려주세요" },
  { id:"consent",     emoji:"✅", title:"마지막으로 동의 내용을 확인해주세요", subtitle:"접수 후 조건에 맞는 업체를 1~3곳으로 추려드려요" },
];

const SERVICE_OPTIONS     = ["유치원","데이케어","호텔링","아직 고민 중"];
const PERSONALITY_OPTIONS = ["활발하고 사교적","겁이 많음","낯가림","분리불안","사회성 부족","짖음이 많음","흥분도가 높음","다른 강아지를 불편해함","사람을 경계함","순하고 무난함"];
const PRIORITY_OPTIONS    = ["가격","집과의 거리","픽업·드랍","야간 상주","사진·알림장","CCTV","소형견 전용","성향 테스트","개별 공간","교육 프로그램"];

const INITIAL_FORM = {
  guardianName:"", phone:"", preferredContact:"카카오톡",
  dogName:"", breed:"", weightKg:"", age:"",
  sex:"", neutered:"", vaccination:"",
  area:"",
  service:[], usagePlan:"", desiredStart:"",
  pickup:"",
  personality:[],
  biteHistory:"", healthNotes:"",
  priority:[],
  budget:"", extraNotes:"",
  privacyConsent:false, partnerShareConsent:false,
};

function normalizePhone(v) {
  const d = v.replace(/\D/g,"").slice(0,11);
  if(d.length<4) return d;
  if(d.length<8) return `${d.slice(0,3)}-${d.slice(3)}`;
  return `${d.slice(0,3)}-${d.slice(3,7)}-${d.slice(7)}`;
}

function makeReceiptId() {
  const n = new Date();
  const d = [n.getFullYear(),String(n.getMonth()+1).padStart(2,"0"),String(n.getDate()).padStart(2,"0")].join("");
  return `PK-${d}-${Math.random().toString(36).slice(2,7).toUpperCase()}`;
}




export default function PetknockForm() {
  const [showWelcome,setShowWelcome] = useState(true);
  const [step,setStep]             = useState(0);
  const [form,setForm]             = useState(INITIAL_FORM);
  const [submitted,setSubmitted]   = useState(false);
  const [receiptId,setReceiptId]   = useState("");
  const [error,setError]           = useState("");
  const [copiedId,setCopiedId]     = useState(false);
  const [isSubmitting,setIsSubmitting] = useState(false);

  const current  = STEPS[step];
  const progress = ((step+1)/STEPS.length)*100;

  const update      = (k,v) => setForm(p=>({...p,[k]:v}));
  const toggleArray = (k,v) => setForm(p=>({...p,[k]:p[k].includes(v)?p[k].filter(i=>i!==v):[...p[k],v]}));

  const validationMessage = useMemo(()=>{
    switch(current.id){
      case "guardian":
        if(!form.guardianName.trim()) return "보호자 이름을 입력해주세요.";
        if(form.phone.replace(/\D/g,"").length<10) return "연락 가능한 휴대폰 번호를 입력해주세요.";
        return "";
      case "dogBasic":
        if(!form.dogName.trim()) return "아이 이름을 입력해주세요.";
        if(!form.breed.trim()) return "견종을 입력해주세요.";
        if(!form.weightKg||Number(form.weightKg)<=0) return "몸무게를 숫자로 입력해주세요.";
        if(!form.age||Number(form.age)<0) return "나이를 숫자로 입력해주세요.";
        return "";
      case "dogCondition":
        if(!form.sex) return "성별을 선택해주세요.";
        if(!form.neutered) return "중성화 여부를 선택해주세요.";
        if(!form.vaccination) return "접종 상태를 선택해주세요.";
        return "";
      case "area":        return form.area.trim()?"":"거주 동네를 입력해주세요.";
      case "service":     return form.service.length?"":"찾는 서비스를 하나 이상 선택해주세요.";
      case "pickup":      return form.pickup?"":"픽업 필요 여부를 선택해주세요.";
      case "personality": return form.personality.length?"":"아이 성향을 하나 이상 선택해주세요.";
      case "health":      return form.biteHistory?"":"입질·공격성 이력을 선택해주세요.";
      case "priority":    return form.priority.length?"":"중요한 조건을 하나 이상 선택해주세요.";
      case "notes":       return "";
      case "consent":     return form.privacyConsent?"":"개인정보 수집·이용 동의가 필요합니다.";
      default:            return "";
    }
  },[current.id,form]);

  const canNext = validationMessage==="";

  const summary = useMemo(()=>[
    `[펫노크 견주 매칭 접수]`,
    `접수번호: ${receiptId||"제출 전"}`,
    `보호자: ${form.guardianName} / ${form.phone} / ${form.preferredContact} 희망`,
    `지역: ${form.area}`,``,
    `반려견: ${form.dogName} / ${form.breed} / ${form.weightKg}kg / ${form.age}살`,
    `성별·중성화: ${form.sex} / ${form.neutered}`,
    `접종: ${form.vaccination}`,
    `성향: ${form.personality.join(", ")||"미입력"}`,
    `입질·공격성: ${form.biteHistory}`,
    `건강 참고: ${form.healthNotes||"없음"}`,``,
    `찾는 서비스: ${form.service.join(", ")}`,
    `이용 형태: ${form.usagePlan||"미정"}`,
    `희망 시기: ${form.desiredStart||"미정"}`,
    `픽업: ${form.pickup}`,
    `중요 조건: ${form.priority.join(", ")}`,
    `예산: ${form.budget||"미정"}`,
    `추가 요청: ${form.extraNotes||"없음"}`,
    `업체 전달 동의: ${form.partnerShareConsent?"동의":"미동의"}`,
  ].join("\n"),[form,receiptId]);

  const submit = async () => {
    if(!canNext || isSubmitting) return;
    setError("");
    setIsSubmitting(true);
    const id = makeReceiptId();
    const payload = {
      receiptId:id,
      submittedAt:new Date().toISOString(),
      source:"petknock-owner-intake",
      ...form,
    };
    try {
      const params = new URLSearchParams();
      params.append("payload", JSON.stringify(payload));
      await fetch(SUBMIT_ENDPOINT, {
        method:"POST",
        mode:"no-cors",
        body:params,
      });
    } catch(e) {
      console.error(e);
    }
    setReceiptId(id);
    setSubmitted(true);
    setIsSubmitting(false);
  };

  const next    = () => { if(isSubmitting) return; setError(""); if(!canNext){setError(validationMessage);return;} step===STEPS.length-1?submit():setStep(p=>p+1); };
  const back    = () => { setError(""); if(submitted){setSubmitted(false);return;} if(step>0)setStep(p=>p-1); };
  const restart = () => { setForm(INITIAL_FORM); setStep(0); setSubmitted(false); setReceiptId(""); setError(""); setIsSubmitting(false); setShowWelcome(true); };
  const copyId  = () => { navigator.clipboard?.writeText(receiptId); setCopiedId(true); setTimeout(()=>setCopiedId(false),2000); };

  // ── 웰컴 화면 ─────────────────────────────────────────────────────────────
  if(showWelcome){
    return(
      <div style={{minHeight:"100vh",background:CREAM,fontFamily:"-apple-system,sans-serif",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:"32px 20px"}}>
        <img src={LOGO} alt="펫노크 로고" style={{width:180,height:180,objectFit:"cover",borderRadius:36,boxShadow:"0 12px 30px rgba(30,71,48,0.10)",marginBottom:24}}/>
        <div style={{color:GREEN,fontSize:22,fontWeight:800,marginBottom:8,textAlign:"center"}}>펫노크</div>
        <div style={{color:MUTED,fontSize:14,lineHeight:1.7,textAlign:"center",marginBottom:36,wordBreak:"keep-all"}}>
          강아지 유치원·호텔링<br/>우리 아이 맞춤 매칭 서비스
        </div>
        <button onClick={()=>setShowWelcome(false)}
          style={{width:"100%",maxWidth:320,padding:"17px",borderRadius:20,border:"none",background:GREEN,color:WHITE,fontSize:16,fontWeight:800,cursor:"pointer"}}>
          우리 아이 정보 입력하기 🐾
        </button>
        <div style={{color:MUTED,fontSize:12,marginTop:16,textAlign:"center"}}>
          동탄 지역 · 무료 매칭 서비스
        </div>
      </div>
    );
  }

// ── 완료 화면 ─────────────────────────────────────────────────────────────
  if(submitted){
    return (
      <div style={{minHeight:"100vh",background:CREAM,fontFamily:"-apple-system,sans-serif"}}>
        <style>{`.pk-fold>summary{list-style:none}.pk-fold>summary::-webkit-details-marker{display:none}.pk-fold .pk-cue{display:inline-block;transition:transform .2s}.pk-fold[open] .pk-cue{transform:rotate(180deg)}`}</style>
        <TopBar progress={100} label="접수 완료" onBack={back} showBack={false} />
        <div style={{maxWidth:520,margin:"0 auto",padding:"20px 16px 48px",display:"flex",flexDirection:"column",gap:14}}>

          {/* 1. 완료 배너 (짧게) */}
          <div style={{background:GREEN,borderRadius:22,padding:"22px 20px",textAlign:"center"}}>
            <div style={{fontSize:44,marginBottom:8}}>🐾</div>
            <div style={{color:WHITE,fontSize:21,fontWeight:800}}>접수가 완료됐어요!</div>
          </div>

          {/* 2. 카톡 상담 시작 — 안내 + 접수번호 + 노란 버튼을 한 덩어리로 */}
          <div style={{background:WHITE,borderRadius:22,padding:"20px 18px",border:`1.5px solid ${TAN}`,display:"flex",flexDirection:"column",gap:15}}>

            {/* 안내 (이득 톤) */}
            <div>
              <div style={{color:GREEN,fontSize:15,fontWeight:800,marginBottom:10,display:"flex",alignItems:"center",gap:6}}>
                <span>💬</span> 상담은 카카오톡으로 진행돼요
              </div>
              <div style={{color:"#555",fontSize:13,lineHeight:1.85}}>
                <div><b style={{color:GREEN}}>①</b> 아래 버튼으로 펫노크 채널을 추가하고</div>
                <div><b style={{color:GREEN}}>②</b> 접수번호를 보내주시면, 담당자가 입력하신 정보로 맞는 곳을 찾아 바로 연락드려요.</div>
              </div>
            </div>

            {/* 접수번호 + 복사 */}
            <div style={{background:CREAM,borderRadius:14,padding:"12px 14px",display:"flex",alignItems:"center",justifyContent:"space-between",gap:10}}>
              <div style={{minWidth:0}}>
                <div style={{color:MUTED,fontSize:10,marginBottom:3,fontWeight:700,letterSpacing:"0.05em"}}>내 접수번호</div>
                <div style={{color:GREEN,fontSize:17,fontWeight:800,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{receiptId}</div>
              </div>
              <button onClick={copyId} style={{padding:"9px 16px",borderRadius:12,border:`1.5px solid ${GREEN}`,background:copiedId?GREEN:WHITE,color:copiedId?WHITE:GREEN,fontSize:12,fontWeight:800,cursor:"pointer",transition:"all 0.2s",flexShrink:0}}>
                {copiedId?"복사됨 ✓":"복사하기"}
              </button>
            </div>

            {/* 노란 카톡 버튼 + 짧은 힌트 */}
            <div>
              <a href={KAKAO_CHAT_URL} target="_blank" rel="noreferrer"
                style={{display:"flex",alignItems:"center",justifyContent:"center",gap:8,padding:"16px",borderRadius:16,background:"#FEE500",color:"#3C1E1E",textDecoration:"none",fontSize:15,fontWeight:800}}>
                <span style={{fontSize:18}}>💬</span> 카카오톡으로 상담 시작하기
              </a>
              <div style={{color:MUTED,fontSize:11,textAlign:"center",marginTop:8}}>
                접수번호를 복사한 뒤 채널 대화창에 붙여넣어 보내주세요
              </div>
            </div>
          </div>

          {/* 3. 접수 내용 — 기본 닫힘(접기) */}
          <details className="pk-fold" style={{background:WHITE,borderRadius:18,border:`0.5px solid ${BORDER}`,overflow:"hidden"}}>
            <summary style={{padding:"15px 18px",color:GREEN,fontWeight:700,fontSize:13,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"space-between"}}>
              <span style={{display:"flex",alignItems:"center",gap:6}}><span>📋</span> 접수 내용 확인하기</span>
              <span className="pk-cue" style={{color:MUTED,fontSize:13}}>▾</span>
            </summary>
            <div style={{padding:"0 18px 18px"}}>
              <pre style={{margin:0,whiteSpace:"pre-wrap",wordBreak:"break-word",fontFamily:"inherit",color:"#444",fontSize:12,lineHeight:1.9}}>{summary}</pre>
            </div>
          </details>

          {/* 4. 다른 아이 입력 */}
          <button onClick={restart} style={{padding:"15px",borderRadius:18,border:`1.5px solid ${GREEN}`,background:"transparent",color:GREEN,fontSize:14,fontWeight:700,cursor:"pointer"}}>
            다른 아이 정보 입력하기
          </button>
        </div>
      </div>
    );
  }
  // ── 스텝 화면 ─────────────────────────────────────────────────────────────
  return (
    <div style={{minHeight:"100vh",background:CREAM,fontFamily:"-apple-system,sans-serif"}}>
      <TopBar progress={progress} label={`${step+1} / ${STEPS.length}`} onBack={back} showBack={step>0} />
      <div style={{maxWidth:520,margin:"0 auto",padding:"28px 16px 100px"}}>

        {/* 질문 헤더 */}
        <div style={{textAlign:"center",marginBottom:24}}>
          <div style={{width:64,height:64,borderRadius:"50%",background:LGREEN,display:"flex",alignItems:"center",justifyContent:"center",fontSize:30,margin:"0 auto 14px"}}>
            {current.emoji}
          </div>
          <div style={{color:GREEN,fontSize:21,fontWeight:800,lineHeight:1.35,wordBreak:"keep-all"}}>{current.title}</div>
          {current.subtitle&&<div style={{color:MUTED,fontSize:13,marginTop:6,lineHeight:1.5}}>{current.subtitle}</div>}
        </div>

        {/* 카드 */}
        <div style={{background:WHITE,borderRadius:24,padding:"20px 18px",border:`0.5px solid ${BORDER}`}}>
          <StepContent stepId={current.id} form={form} update={update} toggleArray={toggleArray}/>
        </div>

        {error&&<div style={{marginTop:12,padding:"11px 14px",borderRadius:14,background:"#FFF0F0",color:"#C0392B",fontSize:13,textAlign:"center"}}>{error}</div>}

        <div style={{display:"flex",gap:10,marginTop:16}}>
          {step>0&&<button onClick={back} style={{flex:"0 0 86px",padding:"15px",borderRadius:20,border:`1.5px solid ${GREEN}`,background:"transparent",color:GREEN,fontSize:14,fontWeight:700,cursor:"pointer"}}>이전</button>}
          <button onClick={next} disabled={isSubmitting}
            style={{flex:1,padding:"16px",borderRadius:20,border:"none",background:isSubmitting?MUTED:GREEN,color:WHITE,fontSize:15,fontWeight:800,cursor:isSubmitting?"wait":"pointer",opacity:isSubmitting?0.85:1}}>
            {isSubmitting?"구글시트에 저장 중...":step===STEPS.length-1?"🐾 접수하기":"다음 →"}
          </button>
        </div>
      </div>
    </div>
  );
}

// ── 상단 바 ──────────────────────────────────────────────────────────────────
function TopBar({progress,label,onBack,showBack}){
  return(
    <div style={{background:GREEN,position:"sticky",top:0,zIndex:20}}>
      <div style={{maxWidth:520,margin:"0 auto",padding:"12px 16px",display:"flex",alignItems:"center",justifyContent:"space-between"}}>
        <div style={{width:32}}>
          {showBack&&<button onClick={onBack} style={{background:"none",border:"none",color:"rgba(255,255,255,0.8)",fontSize:20,cursor:"pointer",padding:0,lineHeight:1}}>←</button>}
        </div>
        <div style={{textAlign:"center"}}>
          <div style={{color:TAN,fontWeight:800,fontSize:13,letterSpacing:"0.15em"}}>🐾 펫노크</div>
          <div style={{color:"rgba(255,255,255,0.7)",fontSize:11,marginTop:2}}>{label}</div>
        </div>
        <div style={{width:32}}/>
      </div>
      <div style={{height:4,background:"rgba(255,255,255,0.15)"}}>
        <div style={{width:`${progress}%`,height:"100%",background:TAN,transition:"width .3s ease",borderRadius:"0 4px 4px 0"}}/>
      </div>
    </div>
  );
}

// ── 스텝 콘텐츠 ──────────────────────────────────────────────────────────────
function StepContent({stepId,form,update,toggleArray}){
  switch(stepId){
    case "guardian": return(
      <div style={S.stack}>
        <Field label="보호자 이름 또는 닉네임"><TextInput value={form.guardianName} onChange={v=>update("guardianName",v)} placeholder="예: 김가루 보호자"/></Field>
        <Field label="휴대폰 번호"><TextInput value={form.phone} onChange={v=>update("phone",normalizePhone(v))} placeholder="010-0000-0000" inputMode="tel"/></Field>
        <Field label="선호 연락 방식"><Chips options={["카카오톡","문자","전화"]} selected={[form.preferredContact]} onClick={v=>update("preferredContact",v)}/></Field>
      </div>
    );
    case "dogBasic": return(
      <div style={S.stack}>
        <Field label="반려견 이름"><TextInput value={form.dogName} onChange={v=>update("dogName",v)} placeholder="예: 가루"/></Field>
        <Field label="견종"><TextInput value={form.breed} onChange={v=>update("breed",v)} placeholder="예: 말티푸, 푸들, 믹스견"/></Field>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
          <Field label="몸무게(kg)"><TextInput value={form.weightKg} onChange={v=>update("weightKg",v.replace(/[^0-9.]/g,""))} placeholder="예: 6" inputMode="decimal"/></Field>
          <Field label="나이(살)"><TextInput value={form.age} onChange={v=>update("age",v.replace(/[^0-9.]/g,""))} placeholder="예: 10" inputMode="decimal"/></Field>
        </div>
      </div>
    );
    case "dogCondition": return(
      <div style={S.stack}>
        <Field label="성별"><Chips options={["남아","여아"]} selected={[form.sex]} onClick={v=>update("sex",v)}/></Field>
        <Field label="중성화 여부"><Chips options={["완료","미완료","예정"]} selected={[form.neutered]} onClick={v=>update("neutered",v)}/></Field>
        <Field label="접종 상태"><Chips options={["필수접종 완료","일부만 완료","미완료","잘 모르겠음"]} selected={[form.vaccination]} onClick={v=>update("vaccination",v)}/></Field>
      </div>
    );
    case "area": return(
      <div style={S.stack}>
        <Field label="거주 동네"><TextInput value={form.area} onChange={v=>update("area",v)} placeholder="예: 반송동, 동탄역, 수원 송죽동"/></Field>
        <div style={{padding:"12px 14px",borderRadius:14,background:LGREEN,color:"#3D6B4A",fontSize:12,lineHeight:1.65}}>
          🗺️ 동탄 외 지역도 괜찮아요. 현재 DB는 동탄 중심이라 거리 탐색이 필요할 수 있어요.
        </div>
      </div>
    );
    case "service": return(
      <div style={S.stack}>
        <Field label="찾는 서비스"><Chips options={SERVICE_OPTIONS} selected={form.service} onClick={v=>toggleArray("service",v)} multi/></Field>
        <Field label="이용 형태"><TextInput value={form.usagePlan} onChange={v=>update("usagePlan",v)} placeholder="예: 주 3회, 가끔 데이케어, 여행 때 호텔링"/></Field>
      </div>
    );
    case "pickup": return <Chips options={["픽업 꼭 필요","가능하면 희망","직접 등하원 가능","아직 미정"]} selected={[form.pickup]} onClick={v=>update("pickup",v)}/>;
    case "personality": return <Chips options={PERSONALITY_OPTIONS} selected={form.personality} onClick={v=>toggleArray("personality",v)} multi/>;
    case "health": return(
      <div style={S.stack}>
        <Field label="입질·공격성 이력이 있나요?"><Chips options={["없음","가끔 경고 행동","입질 이력 있음","잘 모르겠음"]} selected={[form.biteHistory]} onClick={v=>update("biteHistory",v)}/></Field>
        <Field label="질환·복약·수술 이력 등 참고사항"><TextArea value={form.healthNotes} onChange={v=>update("healthNotes",v)} placeholder="예: 슬개골 수술 이력, 심장약 복용 중 / 없으면 비워두셔도 돼요"/></Field>
      </div>
    );
    case "priority": return <Chips options={PRIORITY_OPTIONS} selected={form.priority} onClick={v=>toggleArray("priority",v)} multi/>;
    case "notes": return(
      <div style={S.stack}>
        <Field label="월 예산 또는 1회 예산"><TextInput value={form.budget} onChange={v=>update("budget",v)} placeholder="예: 월 40만원 이하 / 1박 5만원 전후"/></Field>
        <Field label="이용 희망 시기"><TextInput value={form.desiredStart} onChange={v=>update("desiredStart",v)} placeholder="예: 다음 달부터 / 7월 20~22일"/></Field>
        <Field label="추가 요청사항"><TextArea value={form.extraNotes} onChange={v=>update("extraNotes",v)} placeholder="예: 노령견이라 천천히 적응시켜주세요"/></Field>
      </div>
    );
    case "consent": return(
      <div style={S.stack}>
        <ConsentRow checked={form.privacyConsent} onChange={v=>update("privacyConsent",v)} required title="개인정보 수집·이용 동의" desc="맞춤 업체 추천과 상담 연락을 위해 보호자 이름, 연락처, 반려견 정보를 수집합니다."/>
        <ConsentRow checked={form.partnerShareConsent} onChange={v=>update("partnerShareConsent",v)} title="선택 업체에 상담 정보 전달 동의" desc="실제 상담 연결 시 선택 업체에 연락처와 반려견 정보를 전달할 수 있습니다."/>
        <div style={{padding:"12px 14px",borderRadius:14,background:LGREEN,color:"#3D6B4A",fontSize:12,lineHeight:1.65}}>
          🌿 펫노크 추천은 확인된 업체 정보 기반의 비교 안내예요. 최종 입학 가능 여부는 업체 상담 후 결정돼요.
        </div>
      </div>
    );
    default: return null;
  }
}

// ── 공통 컴포넌트 ─────────────────────────────────────────────────────────────
function Field({label,children}){
  return(
    <label style={{display:"block"}}>
      <div style={{color:GREEN,fontWeight:700,fontSize:13,marginBottom:8}}>{label}</div>
      {children}
    </label>
  );
}

function TextInput({value,onChange,placeholder,inputMode}){
  return(
    <input value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder} inputMode={inputMode}
      style={{width:"100%",boxSizing:"border-box",border:`1.5px solid ${BORDER}`,borderRadius:14,padding:"13px 14px",background:CREAM,color:"#222",fontSize:15,outline:"none",fontFamily:"inherit"}}
      onFocus={e=>e.target.style.borderColor=TAN} onBlur={e=>e.target.style.borderColor=BORDER}/>
  );
}

function TextArea({value,onChange,placeholder}){
  return(
    <textarea value={value} onChange={e=>onChange(e.target.value)} placeholder={placeholder} rows={3}
      style={{width:"100%",boxSizing:"border-box",border:`1.5px solid ${BORDER}`,borderRadius:14,padding:"13px 14px",background:CREAM,color:"#222",fontSize:14,outline:"none",fontFamily:"inherit",resize:"vertical",minHeight:90,lineHeight:1.6}}
      onFocus={e=>e.target.style.borderColor=TAN} onBlur={e=>e.target.style.borderColor=BORDER}/>
  );
}

function Chips({options,selected,onClick,multi=false}){
  return(
    <div style={{display:"grid",gridTemplateColumns:"repeat(2,minmax(0,1fr))",gap:9}}>
      {options.map(opt=>{
        const on=selected.includes(opt);
        return(
          <button key={opt} onClick={()=>onClick(opt)} type="button"
            style={{padding:"12px 10px",borderRadius:16,border:`1.5px solid ${on?GREEN:BORDER}`,background:on?GREEN:WHITE,color:on?WHITE:"#444",cursor:"pointer",fontFamily:"inherit",fontSize:13,fontWeight:on?700:500,lineHeight:1.35,display:"flex",alignItems:"center",justifyContent:"space-between",gap:6,textAlign:"left",wordBreak:"keep-all",transition:"all 0.15s"}}>
            <span>{opt}</span>
            {on&&<span style={{color:TAN,fontWeight:900,flexShrink:0}}>{multi?"✓":"●"}</span>}
          </button>
        );
      })}
    </div>
  );
}

function ConsentRow({checked,onChange,title,desc,required=false}){
  return(
    <label style={{display:"flex",alignItems:"flex-start",gap:12,padding:"14px",border:`1px solid ${BORDER}`,borderRadius:16,background:CREAM,cursor:"pointer"}}>
      <input type="checkbox" checked={checked} onChange={e=>onChange(e.target.checked)} style={{width:20,height:20,accentColor:GREEN,flex:"0 0 auto",marginTop:1}}/>
      <span>
        <strong style={{display:"block",color:GREEN,fontSize:13,marginBottom:4}}>{required?"[필수] ":"[선택] "}{title}</strong>
        <span style={{display:"block",color:MUTED,fontSize:12,lineHeight:1.55}}>{desc}</span>
      </span>
    </label>
  );
}

const S = {
  stack:{ display:"flex", flexDirection:"column", gap:20 },
};
